INSERT INTO `jogos` VALUES (1,1,'Assassin\'s Creed Valhalla','Ubisoft Montreal','Ubisoft','Assassin\'s Creed Valhalla é um jogo de ação e aventura em que você é um guerreiro viking que cresceu em meio a histórias de batalhas e glória. Explore um mundo aberto dinâmico, ambientado na Idade das Trevas na Inglaterra.','2020-11-10',' Mínimo Requer: um processador e sistema operacional de 64 bits\nSO Windows 10 (versions 64 bits uniquement)\nProcessador: AMD Ryzen 3 1200 3.1 GHz / Intel Core i5-4460 3.2 GHz\nMemória: 8 GB de RAM\nPlaca de vídeo: AMD R9 380 /NVIDIA GeForce GTX 960\nDirectX: Versão 12\nArmazenamento: 160 GB de espaço disponível\nRecomendado Requer: um processador e sistema operacional de 64 bits\nSO Windows 10 (versions 64 bits uniquement)\nProcessador: AMD Ryzen 5 1600 3.2 GHz / Intel Core i7-4790 3.6 GHz\nMemória: 8 GB de RAM\nPlaca de vídeo: AMD R9 380 /NVIDIA GeForce GTX 960\nDirectX: Versão 12\nArmazenamento: 160 GB de espaço disponível','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Assassin\'s%20Creed%20Valhalla/Assassin\'s%20Creed%20Valhalla%20-%20Capa.png?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Assassin\'s%20Creed%20Valhalla/cenario1creedvalhalla.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Assassin\'s%20Creed%20Valhalla/cenario2creedvalhalla.jpg?raw=true','https://drive.google.com/file/d/1uHePXHeyrYrimFZI4d7bxFwk7e5Sk69x/view?usp=drive_link',290.9),(2,1,'Control','Remedy Entertainment','505 Games','Vencedor de mais de 80 prêmios, o Control é uma aventura de ação em terceira pessoa visualmente impressionante que irá te manter à beira do seu assento.','2019-08-27','Mínimo Requer: um processador e sistema operacional de 64 bits\nSO Windows 7, 64-bit\nProcessador: Intel Core i5-4690 / AMD FX 4350\nMemória: 8 GB de RAM\nPlaca de vídeo: NVIDIA GeForce GTX 780 / AMD Radeon R9 280X\nDirectX: Versão 11\nArmazenamento: 42 GB de espaço disponível\nOutras observações: Additional Features: Widescreen support 21:9 / Remappable controls / Uncapped frame-rate / G-Sync / Freesync support\nRecomendado Requer: um processador e sistema operacional de 64 bits\nSO Windows 10, 64-bit\nProcessador: Intel Core i5-7600K / AMD Ryzen 5 1600X\nMemória: 16 GB de RAM\nPlaca de vídeo: NVIDIA GeForce GTX 1660/1060 / AMD Radeon RX 580 AMD | For Ray Tracing: GeForce RTX 2060\nDirectX: Versão 12\nArmazenamento: 42 GB de espaço disponível\nOutras observações: Additional Features: Widescreen support 21:9 / Remappable controls / Uncapped frame-rate / G-Sync / Freesync support','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Control/Control%20-%20Capa.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Control/cenario1control.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Control/cenario2control.jpg?raw=true','https://drive.google.com/drive/folders/1LVkHim-gYYhSBK32w3Hf55jiv0wYB5Y_?usp=drive_link',99.99),(3,1,'Doom Eternal','id Software','Bethesda Softworks','Os exércitos do Inferno invadiram a Terra. Torne-se o Slayer em uma campanha épica para um jogador e derrote demônios entre dimensões para impedir a derradeira destruição da humanidade. A única coisa que eles temem... é você.','2020-05-20','Mínimo Requer: um processador e sistema operacional de 64 bits\nSO 64-bit Windows 7 / 64-Bit Windows 10\nProcessador: Intel Core i5 @ 3.3 GHz or better, or AMD Ryzen 3 @ 3.1 GHz or better\nMemória: 8 GB de RAM\nPlaca de vídeo: NVIDIA GeForce GTX 1050Ti (4GB), GTX 1060 (3GB), GTX 1650 (4GB) or AMD Radeon R9 280(3GB), AMD Radeon R9 290 (4GB), RX 470 (4GB)\nRede: Conexão de internet banda larga\nArmazenamento: 80 GB de espaço disponível\nOutras observações: ( 1080p / 60 FPS / Low Quality Settings )\nRecomendado Requer: um processador e sistema operacional de 64 bits\nSO 64-bit Windows 10\nProcessador: Intel Core i7-6700K or better, or AMD Ryzen 7 1800X or better\nMemória: 8 GB de RAM\nPlaca de vídeo: NVIDIA GeForce GTX 1060 (6GB), NVIDIA GeForce 970 (4GB), AMD RX 480 (8GB)\nRede: Conexão de internet banda larga\nArmazenamento: 80 GB de espaço disponível\nOutras observações: ( 1080p / 60 FPS / High Quality Settings ) - *On NVIDIA GTX 970 cards Texture Quality should be set to Medium','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Doom%20Eternal/Doom%20Eternal%20-%20Capa.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Doom%20Eternal/cenario1doometernal.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Doom%20Eternal/cenario2doometernal.png?raw=true','https://drive.google.com/file/d/1JcOlktG68dBG3ASdZrVwYIAMDq2CkIsg/view?usp=drive_link',149),(4,1,'Ghost of Tsushima','Sucker Punch Productions, Nixxes Software','PlayStation PC LLC','Uma tempestade se aproxima. Vivencie a experiência completa de Ghost of Tsushima no PC e forje seu próprio caminho neste jogo de ação e aventura de mundo aberto para descobrir suas maravilhosas surpresas. Trazido pela Sucker Punch Productions, Nixxes Software...','2024-05-16','Mínimo Requer: um processador e sistema operacional de 64 bits\nSO Windows 10\nProcessador: Intel Core i3-7100 or AMD Ryzen 3 1200\nMemória: 8 GB de RAM\nPlaca de vídeo: NVIDIA GeForce GTX 960 or AMD Radeon RX 5500 XT\nArmazenamento: 75 GB de espaço disponível\nOutras observações: SSD Recommended\nRecomendado Requer: um processador e sistema operacional de 64 bits\nSO Windows 10\nProcessador: Intel Core i5-8600 or AMD Ryzen 5 3600\nMemória: 16 GB de RAM\nPlaca de vídeo: NVIDIA GeForce RTX 2060 or AMD Radeon RX 5600 XT\nArmazenamento: 75 GB de espaço disponível\nOutras observações: SSD Required','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Ghost%20of%20Tsushima/ghost_capa.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Ghost%20of%20Tsushima/cenario1ghostoftsushima.png?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/Ghost%20of%20Tsushima/cenario2ghostoftsushima.jpg?raw=true','https://drive.google.com/file/d/1n1nO5l3EZFWvBq6vhdIrSA-Grk7VJehz/view?usp=drive_link',249.9),(5,1,'God of war (2018)','Santa Monica Studio, Jetpack Interactive','PlayStation PC LLC','Com a vingança contra os deuses do Olimpo em um passado distante, Kratos agora vive como um mortal no reino dos deuses e monstros nórdicos. É nesse mundo duro e implacável que ele deve lutar para sobreviver... e ensinar seu filho a fazer o mesmo.','2022-01-14','Mínimo Requer: um processador e sistema operacional de 64 bits\nSO Windows 10\nProcessador: Intel i5-2500k (4 core 3.3 GHz) or AMD Ryzen 3 1200 (4 core 3.1 GHz)\nMemória: 8 GB de RAM\nPlaca de vídeo: NVIDIA GTX 960 (4 GB) or AMD R9 290X (4 GB)\nDirectX: Versão 11\nArmazenamento: 70 GB de espaço disponível\nOutras observações: DirectX feature level 11_1 required\nRequisito Requer: um processador e sistema operacional de 64 bits\nSO Windows 10\nProcessador: Intel i5-6600k (4 core 3.5 GHz) or AMD Ryzen 5 2400 G (4 core 3.6 GHz)\nMemória: 8 GB de RAM\nPlaca de vídeo: NVIDIA GTX 1060 (6 GB) or AMD RX 570 (4 GB)\nDirectX: Versão 11\nArmazenamento: 70 GB de espaço disponível\nOutras observações: DirectX feature level 11_1 required','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/God%20Of%20War%20(2018)/capa.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/God%20Of%20War%20(2018)/cenario1gow.jpg?raw=true','https://github.com/Guilherme-odias/ProjIntegrador/blob/master/Imagens%20Jogos/God%20Of%20War%20(2018)/cenario2gow.jpg?raw=true','https://drive.google.com/file/d/1gsIXdU3pTrO2rQ-bOJAW87ha4zPFWh8v/view?usp=drive_link',209.9),(6,1,'GTA V','Rockstar North','Rockstar Games','Aproveite os fenômenos do entretenimento Grand Theft Auto V e G